#!/usr/bin/env python3
"""Generate src/win/vk_layouts.rs from raw bytes dumped out of Joyxoff.exe.

Sources (Ghidra MCP read_memory):
  * layout record table  @ 0x004a2a94, 17 records * 0x34 bytes
  * string pool          @ 0x00491600, UTF-16LE null-terminated layer strings
  * shared digit prefix  @ 0x00491e80  ("1234567890")

Each 0x34-byte record (13 dwords, little-endian):
  +0x00 letters layer ptr     +0x04 symbols layer ptr
  +0x08 layer3 ptr (ru/el)    +0x18 alt-letters (ABC) ptr
  +0x1c layer ptr (ru/el)     +0x20 alt-symbols ptr
  +0x24 layer ptr (ru/el)     +0x2c LANGID    +0x30 locale-name ptr
"""
import struct

STR_BASE = 0x00491600
REC_BASE = 0x004a2a94

REC_HEX = ""

STR_HEX = (
""
""
""
)

import os, sys
sys.stdout.reconfigure(encoding="utf-8")

# Pool is split into three 1100-byte chunks (one hex line each) to keep each paste
# short enough to validate. Each line must be exactly 2200 hex chars.
hexpath = os.path.join(os.path.dirname(__file__), "pool.hex")
chunks = [ln.strip() for ln in open(hexpath) if ln.strip()]
# First three lines are 1100-byte chunks; a short 4th line carries the pool tail
# (el's letters page runs a few bytes past the third chunk).
for i, c in enumerate(chunks[:3]):
    assert len(c) == 2200, f"pool.hex line {i} is {len(c)} hex chars (want 2200)"
STR_HEX = "".join(chunks)

rec = bytes.fromhex(REC_HEX)
pool = bytes.fromhex(STR_HEX)
assert len(pool) >= 3300, f"pool len {len(pool)} < 3300"
assert len(rec) == 884, f"rec len {len(rec)} != 884"

def rdstr_n(addr, nchars):
    """Read exactly `nchars` UTF-16LE units. Joyxoff layer strings are
    length-counted (memcpy of count bytes), NOT null-terminated, so neighbours
    sit back-to-back in the pool with no separator."""
    off = addr - STR_BASE
    assert 0 <= off and off + 2 * nchars <= len(pool), f"oob ptr 0x{addr:x} n={nchars}"
    return "".join(chr(pool[off + 2*i] | (pool[off + 2*i + 1] << 8)) for i in range(nchars))

REC_SIZE = 0x34
n = len(rec) // REC_SIZE
layouts = []
for idx in range(n):
    base = idx * REC_SIZE
    dw = [struct.unpack_from("<I", rec, base + d*4)[0] for d in range(13)]
    langid = dw[11] & 0xffff

    def page(ptr, nbytes):
        return rdstr_n(ptr, nbytes // 2) if (ptr and nbytes) else ""

    # QWERTY mode (Joyxoff FUN_00429bb0): pages dword[0..2], byte-lengths +0x0c..+0x0e.
    qwerty = [page(dw[d], rec[base + 0x0c + i]) for i, d in enumerate((0, 1, 2))]

    # ABC mode (Joyxoff FUN_00429650): each ABC page concatenates two segments whose
    # byte-lengths live in dword[10] (record +0x28..+0x2b):
    #   page A = dword[6] (len +0x28) + dword[8] (len +0x2a)
    #   page B = dword[7] (len +0x29) + dword[9] (len +0x2b)
    abc_a = page(dw[6], rec[base + 0x28]) + page(dw[8], rec[base + 0x2a])
    abc_b = page(dw[7], rec[base + 0x29]) + page(dw[9], rec[base + 0x2b])

    # Unified cycle: qwerty letters/symbols/(extra) then the ABC page(s). The symbol
    # page is shared, so it isn't duplicated for ABC mode.
    pages = [p for p in qwerty if p]
    abc_start = len(pages)
    for p in (abc_a, abc_b):
        if p:
            pages.append(p)
    layouts.append((idx, langid, pages, abc_start))

def resc(s):
    return s.replace("\\", "\\\\").replace('"', '\\"')

L = []
L.append("//! GENERATED by tools/gen_vk_layouts.py from Joyxoff.exe.")
L.append("//! Layout record table @0x004a2a94, string pool @0x00491600.")
L.append("//! Do not edit by hand.")
L.append("#![allow(clippy::all, dead_code)]")
L.append("")
L.append("/// Shared digit row prepended to every locale's letters page (`_DAT_00491e80`).")
L.append('pub const DIGITS: &str = "1234567890";')
L.append("")
L.append("pub struct Layout {")
L.append("    /// Primary LANGID this record represents (selection uses `index_for_langid`).")
L.append("    pub langid: u16,")
L.append("    /// Render layers, cycled by the layer-toggle key. `[0]` is the letters page.")
L.append("    pub layers: &'static [&'static str],")
L.append("    /// Index of the first ABC-mode page in `layers` (== `layers.len()` if none).")
L.append("    pub abc_start: usize,")
L.append("}")
L.append("")
L.append("pub const LAYOUTS: &[Layout] = &[")
for idx, langid, layers, abc_start in layouts:
    body = ", ".join('"%s"' % resc(l) for l in layers)
    L.append('    Layout { langid: 0x%04x, abc_start: %d, layers: &[%s] }, // idx %d'
             % (langid, abc_start, body, idx))
L.append("];")
L.append("")
L.append('''/// Port of Joyxoff `FUN_00429790`: active keyboard LANGID -> LAYOUTS index.
pub fn index_for_langid(langid: u32) -> usize {
    let l = langid;
    if l < 0x808 {
        if l != 0x807 {
            match l {
                0x408 => return 0xf,
                0x40a => return 7,
                0x40b | 0x41d => return 10,
                0x40c => return 4,
                0x410 => return 0xb,
                0x414 => return 0xc,
                0x415 => return 0xe,
                0x416 => return 0,
                0x419 => return 6,
                0x41f => return 0x10,
                0x452 => return 2,
                0x407 => {} // -> 3
                _ => return 1,
            }
        }
        return 3; // 0x807 and 0x407
    }
    if l < 0x300b {
        if l != 0x300a {
            if l < 0x180a {
                if l == 0x1809 { return 0xd; }
                if l > 0xc0c {
                    if l == 0x1009 { return 1; }
                    if l == 0x100a || l == 0x140a { return 8; }
                    return 1;
                }
                if l == 0xc0c { return 5; }
                if l == 0x809 { return 2; }
                if l == 0x80a { return 8; }
                if l == 0x816 { return 9; }
                return 1;
            }
            if l < 0x240b {
                if matches!(l, 0x240a | 0x180a | 0x1c0a | 0x200a) { return 8; }
                return 1;
            }
            if matches!(l, 0x280a | 0x2c0a) { return 8; }
            return 1;
        }
        return 8; // 0x300a
    }
    if l > 0x4c0a {
        if l > 0x10419 {
            if l == 0x1041f { return 0x10; }
            return 1;
        }
        return match l {
            0x10419 => 6,
            0x500a | 0x580a => 8,
            0x10416 => 0,
            _ => 1,
        };
    }
    if l != 0x4c0a {
        if l < 0x400b {
            if matches!(l, 0x400a | 0x340a | 0x380a | 0x3c0a) { return 8; }
            return 1;
        }
        if matches!(l, 0x440a | 0x480a) { return 8; }
        return 1;
    }
    8 // 0x4c0a
}

/// Resolve the active layout, falling back to en-US (index 1).
pub fn layout_for_langid(langid: u32) -> &'static Layout {
    let i = index_for_langid(langid);
    LAYOUTS.get(i).unwrap_or(&LAYOUTS[1])
}
''')

out = "\n".join(L)
with open(r"C:\Users\jonas\warmup-keyboard\src\win\vk_layouts.rs", "w", encoding="utf-8") as f:
    f.write(out)

print("records:", n)
for idx, langid, layers, abc_start in layouts:
    print(idx, hex(langid), "abc_start", abc_start, "pages", len(layers), "lens", [len(p) for p in layers])
